from typing import Dict, List, Optional, Any
from enum import Enum
from datetime import datetime

class UserTier(Enum):
    GUEST = "guest"
    BASIC = "basic"
    PREMIUM = "premium"
    ADMIN = "admin"

class DiscountType(Enum):
    PERCENTAGE = "percentage"
    FIXED = "fixed"

class CheckoutError(Exception):
    pass

class ValidationError(CheckoutError):
    pass

class DiscountError(CheckoutError):
    pass

class PaymentError(CheckoutError):
    pass

def multi_step_checkout(
    cart_items: List[Dict[str, Any]],
    user_info: Dict[str, Any],
    discount_code: Optional[str] = None,
    payment_method: Dict[str, Any] = None,
    tax_rate: float = 0.0
) -> Dict[str, Any]:
    
    # Step 1: Validate cart items
    validated_cart = validate_cart_items(cart_items)
    
    # Step 2: Apply discount codes
    discounted_cart = apply_discount_codes(validated_cart, discount_code, user_info)
    
    # Step 3: Calculate tax
    cart_with_tax = calculate_tax(discounted_cart, tax_rate)
    
    # Step 4: Process payment
    payment_result = process_payment(cart_with_tax, payment_method, user_info)
    
    # Step 5: Create order record
    order_record = create_order_record(cart_with_tax, payment_result, user_info, discount_code)
    
    return order_record

def validate_cart_items(cart_items: List[Dict[str, Any]]) -> Dict[str, Any]:
    if not cart_items:
        raise ValidationError("Cart is empty")
    
    validated_items = []
    subtotal = 0.0
    
    for item in cart_items:
        if not isinstance(item, dict):
            raise ValidationError(f"Invalid item format: {item}")
        
        required_fields = ['id', 'name', 'price', 'quantity']
        for field in required_fields:
            if field not in item:
                raise ValidationError(f"Missing required field '{field}' in item")
        
        if not isinstance(item['price'], (int, float)) or item['price'] < 0:
            raise ValidationError(f"Invalid price for item {item['id']}: {item['price']}")
        
        if not isinstance(item['quantity'], int) or item['quantity'] <= 0:
            raise ValidationError(f"Invalid quantity for item {item['id']}: {item['quantity']}")
        
        item_total = item['price'] * item['quantity']
        
        validated_item = {
            'id': item['id'],
            'name': item['name'],
            'price': float(item['price']),
            'quantity': int(item['quantity']),
            'item_total': item_total
        }
        
        validated_items.append(validated_item)
        subtotal += item_total
    
    return {
        'items': validated_items,
        'subtotal': subtotal,
        'discount_amount': 0.0,
        'discount_code': None
    }

def apply_discount_codes(
    cart_data: Dict[str, Any],
    discount_code: Optional[str],
    user_info: Dict[str, Any]
) -> Dict[str, Any]:
    
    if not discount_code:
        return cart_data
    
    # Define available discount codes with their rules
    discount_codes = {
        'SAVE10': {
            'type': DiscountType.PERCENTAGE,
            'value': 10,
            'min_tier': UserTier.GUEST,
            'min_purchase': 0
        },
        'SAVE20': {
            'type': DiscountType.PERCENTAGE,
            'value': 20,
            'min_tier': UserTier.BASIC,
            'min_purchase': 50
        },
        'PREMIUM50': {
            'type': DiscountType.FIXED,
            'value': 50,
            'min_tier': UserTier.PREMIUM,
            'min_purchase': 100
        },
        'ADMIN100': {
            'type': DiscountType.FIXED,
            'value': 100,
            'min_tier': UserTier.ADMIN,
            'min_purchase': 0
        },
        'ADMINALL': {
            'type': DiscountType.PERCENTAGE,
            'value': 100,
            'min_tier': UserTier.ADMIN,
            'min_purchase': 0
        }
    }
    
    if discount_code not in discount_codes:
        raise DiscountError(f"Invalid discount code: {discount_code}")
    
    discount_info = discount_codes[discount_code]
    
    # Get user tier
    user_tier_str = user_info.get('tier', 'guest')
    try:
        user_tier = UserTier(user_tier_str.lower())
    except ValueError:
        user_tier = UserTier.GUEST
    
    # Define tier hierarchy
    tier_hierarchy = {
        UserTier.GUEST: 0,
        UserTier.BASIC: 1,
        UserTier.PREMIUM: 2,
        UserTier.ADMIN: 3
    }
    
    # Check user permission
    if tier_hierarchy[user_tier] < tier_hierarchy[discount_info['min_tier']]:
        raise DiscountError(
            f"User tier '{user_tier.value}' is not authorized to use discount code '{discount_code}'. "
            f"Minimum tier required: '{discount_info['min_tier'].value}'"
        )
    
    # Check minimum purchase requirement
    if cart_data['subtotal'] < discount_info['min_purchase']:
        raise DiscountError(
            f"Minimum purchase of ${discount_info['min_purchase']} required for discount code '{discount_code}'. "
            f"Current subtotal: ${cart_data['subtotal']:.2f}"
        )
    
    # Calculate discount
    if discount_info['type'] == DiscountType.PERCENTAGE:
        discount_amount = cart_data['subtotal'] * (discount_info['value'] / 100)
    else:  # FIXED
        discount_amount = min(discount_info['value'], cart_data['subtotal'])
    
    cart_data['discount_amount'] = discount_amount
    cart_data['discount_code'] = discount_code
    
    return cart_data

def calculate_tax(cart_data: Dict[str, Any], tax_rate: float) -> Dict[str, Any]:
    if tax_rate < 0 or tax_rate > 1:
        raise ValidationError(f"Invalid tax rate: {tax_rate}. Must be between 0 and 1")
    
    taxable_amount = cart_data['subtotal'] - cart_data['discount_amount']
    tax_amount = taxable_amount * tax_rate
    total = taxable_amount + tax_amount
    
    cart_data['tax_rate'] = tax_rate
    cart_data['tax_amount'] = tax_amount
    cart_data['total'] = total
    
    return cart_data

def process_payment(
    cart_data: Dict[str, Any],
    payment_method: Dict[str, Any],
    user_info: Dict[str, Any]
) -> Dict[str, Any]:
    
    if not payment_method:
        raise PaymentError("Payment method is required")
    
    required_payment_fields = ['type', 'details']
    for field in required_payment_fields:
        if field not in payment_method:
            raise PaymentError(f"Missing required payment field: {field}")
    
    payment_type = payment_method['type']
    
    if payment_type == 'credit_card':
        details = payment_method['details']
        required_cc_fields = ['card_number', 'cvv', 'expiry']
        for field in required_cc_fields:
            if field not in details:
                raise PaymentError(f"Missing credit card field: {field}")
        
        # Simulate card validation
        if len(str(details['card_number'])) < 13:
            raise PaymentError("Invalid card number")
        
    elif payment_type == 'paypal':
        details = payment_method['details']
        if 'email' not in details:
            raise PaymentError("PayPal email required")
    
    elif payment_type == 'bank_transfer':
        details = payment_method['details']
        if 'account_number' not in details:
            raise PaymentError("Bank account number required")
    
    else:
        raise PaymentError(f"Unsupported payment type: {payment_type}")
    
    # Simulate payment processing
    payment_result = {
        'payment_id': f"PAY-{datetime.now().timestamp():.0f}",
        'status': 'completed',
        'amount': cart_data['total'],
        'payment_type': payment_type,
        'timestamp': datetime.now().isoformat()
    }
    
    return payment_result

def create_order_record(
    cart_data: Dict[str, Any],
    payment_result: Dict[str, Any],
    user_info: Dict[str, Any],
    discount_code: Optional[str]
) -> Dict[str, Any]:
    
    order_id = f"ORD-{datetime.now().timestamp():.0f}"
    
    order_record = {
        'order_id': order_id,
        'user_id': user_info.get('user_id', 'guest'),
        'user_email': user_info.get('email', ''),
        'user_tier': user_info.get('tier', 'guest'),
        'items': cart_data['items'],
        'subtotal': cart_data['subtotal'],
        'discount_code': discount_code,
        'discount_amount': cart_data['discount_amount'],
        'tax_rate': cart_data['tax_rate'],
        'tax_amount': cart_data['tax_amount'],
        'total': cart_data['total'],
        'payment': payment_result,
        'status': 'confirmed',
        'created_at': datetime.now().isoformat(),
        'updated_at': datetime.now().isoformat()
    }
    
    return order_record